package com.example.myapp; // Replace with your actual package name

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import java.util.List;

public class DeepLinkHandlerActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        Intent intent = getIntent();
        if (Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri uri = intent.getData();
            if (uri != null) {
                handleDeepLink(uri);
            }
        }
        // Always finish this activity to prevent it from staying in the back stack
        finish();
    }

    private void handleDeepLink(Uri uri) {
        String scheme = uri.getScheme(); // "myapp"
        String host = uri.getHost();     // "profile", "payment", "admin", etc.
        List<String> pathSegments = uri.getPathSegments(); // ["123"], ["confirm"], ["settings"]

        Intent targetIntent = null;

        if ("myapp".equals(scheme)) {
            if ("profile".equals(host)) {
                if (!pathSegments.isEmpty()) {
                    String profileId = pathSegments.get(0);
                    targetIntent = new Intent(this, ProfileActivity.class);
                    targetIntent.putExtra("profile_id", profileId);
                } else {
                    // Handle myapp://profile (no ID) - maybe show a list of profiles
                    targetIntent = new Intent(this, ProfileActivity.class);
                }
            } else if ("payment".equals(host)) {
                if (!pathSegments.isEmpty() && "confirm".equals(pathSegments.get(0))) {
                    // Handle myapp://payment/confirm
                    targetIntent = new Intent(this, PaymentActivity.class);
                    targetIntent.putExtra("action", "confirm");
                } else {
                    // Handle myapp://payment or other payment related links
                    targetIntent = new Intent(this, PaymentActivity.class);
                }
            } else if ("admin".equals(host)) {
                if (!pathSegments.isEmpty() && "settings".equals(pathSegments.get(0))) {
                    // Handle myapp://admin/settings
                    targetIntent = new Intent(this, AdminActivity.class);
                    targetIntent.putExtra("screen", "settings");
                } else {
                    // Handle myapp://admin or other admin related links
                    targetIntent = new Intent(this, AdminActivity.class);
                }
            }
            // Add more conditions for other hosts/paths as needed
            // else if ("another_feature".equals(host)) { ... }

            if (targetIntent != null) {
                // Ensure the new activity starts in a fresh task if the app is not running
                targetIntent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
                startActivity(targetIntent);
            } else {
                // If no specific handler found, navigate to the main activity or a default screen
                startActivity(new Intent(this, MainActivity.class));
            }
        } else {
            // Unexpected scheme, navigate to main activity
            startActivity(new Intent(this, MainActivity.class));
        }
    }
}

