package com.example.myapp; // Replace with your actual package name

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class ProfileActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_profile);

        TextView profileIdTextView = findViewById(R.id.profile_id_text);

        String profileId = getIntent().getStringExtra("profile_id");
        if (profileId != null) {
            profileIdTextView.setText("Viewing Profile ID: " + profileId);
        } else {
            profileIdTextView.setText("Viewing generic Profile screen.");
        }
    }
}

